"""
Benchmark runner — iterates QA pairs through a strategy and saves predictions.

Output format (one JSON object per line — JSONL):
  results/predictions_naive.jsonl
  results/predictions_hybrid.jsonl
  ...

Each line:
{
  "id": "...",
  "question": "...",
  "answer": "...",           <- generated by the strategy
  "contexts": [...],         <- chunks retrieved and fed to the LLM
  "reference_answer": "...", <- ground truth (for RAGAS answer_correctness)
  "reference_contexts": [...],  <- ground truth passages (for context_recall)
  "strategy": "naive",
  "latency_ms": 342.1,
  "cost_usd": 0.00012,
  "prompt_tokens": 890,
  "completion_tokens": 47,
  "metadata": {...}
}
"""
from __future__ import annotations

import json
import time
from pathlib import Path

from rich.console import Console
from rich.progress import (
    BarColumn,
    MofNCompleteColumn,
    Progress,
    SpinnerColumn,
    TextColumn,
    TimeElapsedColumn,
    TimeRemainingColumn,
)
from rich.table import Table

from rag_eval.datasets import QAPair
from rag_eval.strategies.base import BaseStrategy

console = Console()


def run_strategy(
    strategy: BaseStrategy,
    qa_pairs: list[QAPair],
    output_dir: Path,
) -> Path:
    """
    Run a strategy over all QA pairs and write predictions to JSONL.

    Args:
        strategy:   Instantiated strategy (NaiveRAG, HybridRAG, etc.).
        qa_pairs:   List of QA pairs from load_hotpotqa().
        output_dir: Directory to write predictions_{strategy.name}.jsonl.

    Returns:
        Path to the written predictions file.
    """
    output_dir = Path(output_dir)
    output_dir.mkdir(parents=True, exist_ok=True)
    output_file = output_dir / f"predictions_{strategy.name}.jsonl"

    predictions = []
    errors = 0

    with Progress(
        SpinnerColumn(),
        TextColumn(f"[cyan]{strategy.name}[/] {{task.description}}"),
        BarColumn(),
        MofNCompleteColumn(),
        TimeElapsedColumn(),
        TimeRemainingColumn(),
        console=console,
    ) as progress:
        task = progress.add_task("Generating answers...", total=len(qa_pairs))

        for qa in qa_pairs:
            try:
                result = strategy.answer(qa["question"])

                predictions.append({
                    "id": qa["id"],
                    "question": qa["question"],
                    "answer": result.answer,
                    "contexts": result.contexts,
                    "reference_answer": qa["reference_answer"],
                    "reference_contexts": qa["reference_contexts"],
                    "strategy": strategy.name,
                    "latency_ms": round(result.latency_ms, 2),
                    "cost_usd": round(result.cost_usd, 6),
                    "prompt_tokens": result.prompt_tokens,
                    "completion_tokens": result.completion_tokens,
                    "metadata": result.metadata,
                })

            except Exception as exc:
                errors += 1
                # Log the error but keep going — don't abort a 500-question run
                # because one query failed (e.g. rate limit, timeout)
                predictions.append({
                    "id": qa["id"],
                    "question": qa["question"],
                    "answer": "",
                    "contexts": [],
                    "reference_answer": qa["reference_answer"],
                    "reference_contexts": qa["reference_contexts"],
                    "strategy": strategy.name,
                    "latency_ms": 0.0,
                    "cost_usd": 0.0,
                    "prompt_tokens": 0,
                    "completion_tokens": 0,
                    "metadata": {"error": str(exc)},
                })

            progress.advance(task)

    # Write JSONL
    with open(output_file, "w", encoding="utf-8") as f:
        for pred in predictions:
            f.write(json.dumps(pred, ensure_ascii=False) + "\n")

    # Print run summary
    telemetry = strategy.tracker.summary()
    _print_run_summary(strategy.name, len(predictions), errors, output_file, telemetry)

    return output_file


def _print_run_summary(
    strategy_name: str,
    total: int,
    errors: int,
    output_file: Path,
    telemetry: dict,
) -> None:
    table = Table(
        title=f"Run summary: {strategy_name}",
        show_header=True,
        header_style="bold cyan",
    )
    table.add_column("Metric", style="cyan")
    table.add_column("Value", justify="right")

    table.add_row("Total queries", str(total))
    table.add_row("Errors", str(errors))
    if telemetry:
        table.add_row("Latency p50", f"{telemetry.get('latency_p50_ms', '-')} ms")
        table.add_row("Latency p95", f"{telemetry.get('latency_p95_ms', '-')} ms")
        table.add_row("Total cost", f"${telemetry.get('total_cost_usd', 0):.4f}")
        table.add_row("Cost / 1K queries", f"${telemetry.get('cost_per_1k_queries_usd', 0):.4f}")
    table.add_row("Output file", str(output_file))

    console.print(table)
